  const checkUser = async () => {
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) {
        navigate("/auth");
        return;
      }
      setUser(session.user);
    } catch (error) {
      console.error("Error checking auth status:", error);
      navigate("/auth");
    } finally {
      setLoading(false);
    }
  };

